.darma-loader-uiverse-orbital-button-spinner {
      position: relative;
      display: inline-block;
      width: 34px;
      height: 34px;
      border-radius: 50%;
      border: 1px solid color-mix(in srgb, var(--loader-color, #ec4899) 24%, transparent);
    }
    .darma-loader-uiverse-orbital-button-spinner i {
      position: absolute;
      inset: -3px;
      border-radius: 50%;
      animation: darma-loader-uiverse-orbital-button-spinner-orbit 0.8s linear infinite;
    }
    .darma-loader-uiverse-orbital-button-spinner i::before {
      content: "";
      position: absolute;
      top: 0;
      left: 50%;
      width: 10px;
      height: 10px;
      margin-left: -5px;
      border-radius: 50%;
      background: var(--loader-color, #ec4899);
      box-shadow: 0 0 18px color-mix(in srgb, var(--loader-color, #ec4899) 45%, transparent);
    }
    .darma-loader-uiverse-orbital-button-spinner i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-uiverse-orbital-button-spinner i:nth-child(2) { animation-delay: -0.40s; }
    @keyframes darma-loader-uiverse-orbital-button-spinner-orbit { to { transform: rotate(360deg); } }

